    10→)
    11→
    12→const defaultECRPublicURL = "https://public.ecr.aws"
    13→const ecrGalleryAPI = "https://api.us-east-1.gallery.ecr.aws"
    14→
    15→// ECRPublicSource polls AWS ECR Public Gallery for new image tags
    16→// using the ECR Public Gallery API which returns pushed timestamps directly.
    17→type ECRPublicSource struct {
    18→	client     *http.Client
    19→	repository string // "registry_alias/repo_name", e.g. "i6b2w2n6/op-node"
    20→	baseURL    string
    21→	galleryURL string
    22→	sourceID   string
    23→}
    24→
    25→func NewECRPublicSource(client *http.Client, repository string, sourceID string) *ECRPublicSource {
    26→	return &ECRPublicSource{
    27→		client:     client,
    28→		repository: repository,
    29→		baseURL:    defaultECRPublicURL,
    30→		galleryURL: ecrGalleryAPI,
    31→		sourceID:   sourceID,
    32→	}
    33→}
    34→
    35→func (s *ECRPublicSource) Name() string    { return "ecr-public" }
    36→func (s *ECRPublicSource) SourceID() string { return s.sourceID }
    37→
    38→// ecrImageTagDetail represents a single tag from the ECR Gallery API response.
    39→type ecrImageTagDetail struct {
    40→	ImageTag string `json:"imageTag"`
    41→	Detail   struct {
    42→		ImagePushedAt string `json:"imagePushedAt"`
    43→	} `json:"imageDetail"`
    44→}
    45→
    46→func (s *ECRPublicSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    47→	// Parse "alias/repo" into separate fields for the Gallery API.
    48→	alias, repo, err := splitRepository(s.repository)
    49→	if err != nil {
    50→		return nil, err
    51→	}
    52→
    53→	var allTags []ecrImageTagDetail
    54→	var nextToken string
    55→
    56→	for {
    57→		tags, token, err := s.fetchImageTags(ctx, alias, repo, nextToken)
    58→		if err != nil {
    59→			return nil, fmt.Errorf("fetch image tags: %w", err)
    60→		}
    61→		allTags = append(allTags, tags...)
    62→		if token == "" {
    63→			break
    64→		}
    65→		nextToken = token
    66→	}
    67→
    68→	results := make([]IngestionResult, 0, len(allTags))
    69→	for _, tag := range allTags {
    70→		ts, _ := time.Parse(time.RFC3339Nano, tag.Detail.ImagePushedAt)
    71→		if ts.IsZero() {
    72→			ts = time.Now()
    73→		}
    74→		results = append(results, IngestionResult{
    75→			Repository: s.repository,
    76→			RawVersion: tag.ImageTag,
    77→			Timestamp:  ts,
    78→		})
    79→	}
    80→	return results, nil
    81→}
    82→
    83→// fetchImageTags calls the ECR Public Gallery API to list image tags with pushed timestamps.
    84→func (s *ECRPublicSource) fetchImageTags(ctx context.Context, alias, repo, nextToken string) ([]ecrImageTagDetail, string, error) {
    85→	payload := map[string]interface{}{
    86→		"registryAliasName": alias,
    87→		"repositoryName":    repo,
    88→		"maxResults":        100,
    89→	}
    90→	if nextToken != "" {
    91→		payload["nextToken"] = nextToken
    92→	}
    93→
    94→	body, err := json.Marshal(payload)
    95→	if err != nil {
    96→		return nil, "", err
    97→	}
    98→
    99→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, s.galleryURL+"/describeImageTags", bytes.NewReader(body))
   100→	if err != nil {
   101→		return nil, "", err
   102→	}
   103→	req.Header.Set("Content-Type", "application/json")
   104→
   105→	resp, err := s.client.Do(req)
   106→	if err != nil {
   107→		return nil, "", err
   108→	}
   109→	defer resp.Body.Close()
   110→
   111→	if resp.StatusCode != http.StatusOK {
   112→		return nil, "", fmt.Errorf("gallery API status %d", resp.StatusCode)
   113→	}
   114→
   115→	var result struct {
   116→		ImageTagDetails []ecrImageTagDetail `json:"imageTagDetails"`
   117→		NextToken       string              `json:"nextToken"`
   118→	}
   119→	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
   120→		return nil, "", err
   121→	}
   122→	return result.ImageTagDetails, result.NextToken, nil
   123→}
   124→
   125→// splitRepository splits "alias/repo" into its two components.
   126→func splitRepository(repository string) (alias, repo string, err error) {
   127→	for i, c := range repository {
   128→		if c == '/' {
   129→			return repository[:i], repository[i+1:], nil
   130→		}
   131→	}
   132→	return "", "", fmt.Errorf("ecr-public repository must be alias/repo, got %q", repository)
   133→}
