    13→// SourcesStore defines the persistence operations for sources.
    14→type SourcesStore interface {
    15→	ListSourcesByProject(ctx context.Context, projectID string, page, perPage int) ([]models.Source, int, error)
    16→	CreateSource(ctx context.Context, src *models.Source) error
    17→	GetSource(ctx context.Context, id string) (*models.Source, error)
    18→	UpdateSource(ctx context.Context, id string, src *models.Source) error
    19→	DeleteSource(ctx context.Context, id string) error
    20→}
    21→
    22→// SourcesHandler implements HTTP handlers for the /sources resource.
    23→type SourcesHandler struct {
    24→	store            SourcesStore
    25→	ingestionService *ingestion.Service
    26→	httpClient       *http.Client
    27→}
    28→
    29→// NewSourcesHandler returns a new SourcesHandler.
    30→func NewSourcesHandler(store SourcesStore, ingestionService *ingestion.Service, httpClient *http.Client) *SourcesHandler {
    31→	return &SourcesHandler{store: store, ingestionService: ingestionService, httpClient: httpClient}
    32→}
    33→
    34→// List handles GET /projects/{projectId}/sources — returns a paginated list of sources for a project.
    35→func (h *SourcesHandler) List(w http.ResponseWriter, r *http.Request) {
    36→	projectID := r.PathValue("projectId")
    37→	if projectID == "" {
    38→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    39→		return
    40→	}
    41→	page, perPage := ParsePagination(r)
    42→	sources, total, err := h.store.ListSourcesByProject(r.Context(), projectID, page, perPage)
    43→	if err != nil {
    44→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list sources")
    45→		return
    46→	}
    47→	if sources == nil {
    48→		sources = []models.Source{}
    49→	}
    50→	RespondList(w, r, http.StatusOK, sources, page, perPage, total)
    51→}
    52→
    53→// Create handles POST /projects/{projectId}/sources — creates a new source under a project.
    54→func (h *SourcesHandler) Create(w http.ResponseWriter, r *http.Request) {
    55→	projectID := r.PathValue("projectId")
    56→	if projectID == "" {
    57→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    58→		return
    59→	}
    60→	var src models.Source
    61→	if err := DecodeJSON(r, &src); err != nil {
    62→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    63→		return
    64→	}
    65→	src.ProjectID = projectID
    66→	src.Provider = strings.TrimSpace(src.Provider)
    67→	src.Repository = strings.TrimSpace(src.Repository)
    68→	if src.Provider == "" {
    69→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "provider is required")
    70→		return
    71→	}
    72→	if src.Repository == "" {
    73→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "repository is required")
    74→		return
    75→	}
    76→	if err := h.store.CreateSource(r.Context(), &src); err != nil {
    77→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create source")
    78→		return
    79→	}
    80→	RespondJSON(w, r, http.StatusCreated, src)
    81→}
    82→
    83→// Get handles GET /sources/{id} — returns a single source.
    84→func (h *SourcesHandler) Get(w http.ResponseWriter, r *http.Request) {
    85→	id := r.PathValue("id")
    86→	if id == "" {
    87→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
    88→		return
    89→	}
    90→	src, err := h.store.GetSource(r.Context(), id)
    91→	if err != nil {
    92→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
    93→		return
    94→	}
    95→	RespondJSON(w, r, http.StatusOK, src)
    96→}
    97→
    98→// Update handles PUT /sources/{id} — updates an existing source.
    99→func (h *SourcesHandler) Update(w http.ResponseWriter, r *http.Request) {
   100→	id := r.PathValue("id")
   101→	if id == "" {
   102→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
   103→		return
   104→	}
   105→	var src models.Source
   106→	if err := DecodeJSON(r, &src); err != nil {
   107→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   108→		return
   109→	}
   110→	src.Provider = strings.TrimSpace(src.Provider)
   111→	src.Repository = strings.TrimSpace(src.Repository)
   112→	if src.Provider == "" {
   113→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "provider is required")
   114→		return
   115→	}
   116→	if src.Repository == "" {
   117→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "repository is required")
   118→		return
   119→	}
   120→	if err := h.store.UpdateSource(r.Context(), id, &src); err != nil {
   121→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
   122→		return
   123→	}
   124→	src.ID = id
   125→	RespondJSON(w, r, http.StatusOK, src)
   126→}
   127→
   128→// Delete handles DELETE /sources/{id} — deletes a source.
   129→func (h *SourcesHandler) Delete(w http.ResponseWriter, r *http.Request) {
   130→	id := r.PathValue("id")
   131→	if id == "" {
   132→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
   133→		return
   134→	}
   135→	if err := h.store.DeleteSource(r.Context(), id); err != nil {
   136→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
   137→		return
   138→	}
   139→	w.WriteHeader(http.StatusNoContent)
   140→}
   141→
   142→// FetchReleases handles POST /sources/{id}/releases — polls upstream for new
   143→// releases and ingests them immediately.
   144→func (h *SourcesHandler) FetchReleases(w http.ResponseWriter, r *http.Request) {
   145→	id := r.PathValue("id")
   146→	if id == "" {
   147→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid source ID")
   148→		return
   149→	}
   150→	src, err := h.store.GetSource(r.Context(), id)
   151→	if err != nil {
   152→		RespondError(w, r, http.StatusNotFound, "not_found", "Source not found")
   153→		return
   154→	}
   155→
   156→	ingestionSrc := ingestion.BuildSource(h.httpClient, src.ID, src.Provider, src.Repository)
   157→	if ingestionSrc == nil {
   158→		RespondError(w, r, http.StatusUnprocessableEntity, "unsupported_provider", "Unsupported provider: "+src.Provider)
   159→		return
   160→	}
   161→
   162→	results, err := ingestionSrc.FetchNewReleases(r.Context())
   163→	if err != nil {
   164→		slog.Error("fetch releases failed", "source", src.ID, "err", err)
   165→		RespondError(w, r, http.StatusBadGateway, "upstream_error", "Failed to fetch releases from upstream")
   166→		return
   167→	}
   168→
   169→	newCount := 0
   170→	if len(results) > 0 && h.ingestionService != nil {
   171→		for _, result := range results {
   172→			if procErr := h.ingestionService.ProcessResults(r.Context(), src.ID, src.Provider, []ingestion.IngestionResult{result}); procErr != nil {
   173→				slog.Error("process release failed", "source", src.ID, "version", result.RawVersion, "err", procErr)
   174→				continue
   175→			}
   176→			newCount++
   177→		}
   178→	}
   179→
   180→	RespondJSON(w, r, http.StatusOK, map[string]int{"new_releases": newCount})
   181→}
   182→

