    17→interface SourceWithProject extends Source {
    18→  projectName?: string;
    19→}
    20→
    21→export default function SourcesPage() {
    22→  const { data: projectsData } = useSWR("projects-for-sources", () => projectsApi.list());
    23→
    24→  const { data: allSources, isLoading } = useSWR(
    25→    projectsData ? "all-sources" : null,
    26→    async () => {
    27→      if (!projectsData?.data?.length) return [];
    28→      const results = await Promise.all(
    29→        projectsData.data.map(async (p) => {
    30→          const res = await sourcesApi.listByProject(p.id).catch(() => null);
    31→          return (res?.data ?? []).map((s) => ({ ...s, projectName: p.name }));
    32→        })
    33→      );
    34→      return results.flat() as SourceWithProject[];
    35→    }
    36→  );
    37→
    38→  const [editingSource, setEditingSource] = useState<SourceWithProject | null>(null);
    39→  const [deletingId, setDeletingId] = useState<string | null>(null);
