    48→      return;
    49→    }
    50→
    51→    let parsedConfig: Record<string, unknown> | undefined;
    52→    if (configJson.trim() && configJson.trim() !== "{}") {
    53→      try {
    54→        parsedConfig = JSON.parse(configJson);
    55→      } catch {
    56→        setError("Config must be valid JSON");
    57→        return;
    58→      }
    59→    }
    60→
    61→    setSaving(true);
    62→    try {
    63→      await onSubmit({
    64→        provider,
    65→        repository: repository.trim(),
