   110→      </div>
   111→      <div className="space-y-2">
   112→        <Label htmlFor="poll_interval">Poll Interval (seconds)</Label>
   113→        <Input id="poll_interval" type="number" min={60} value={pollInterval} onChange={(e) => setPollInterval(e.target.value)} />
   114→      </div>
   115→      <div className="space-y-2">
   116→        <Label htmlFor="config">Config (JSON, optional)</Label>
   117→        <Textarea
   118→          id="config"
   119→          value={configJson}
   120→          onChange={(e) => setConfigJson(e.target.value)}
   121→          rows={4}
   122→          className="font-mono text-sm"
   123→          placeholder="{}"
   124→        />
   125→      </div>
   126→      <div className="space-y-2">
   127→        <Label htmlFor="version_filter_include">Version Filter — Include (regex, optional)</Label>
   128→        <Input
   129→          id="version_filter_include"
   130→          value={versionFilterInclude}
   131→          onChange={(e) => setVersionFilterInclude(e.target.value)}
   132→          placeholder='e.g. ^v\d+\.\d+\.\d+$'
   133→          className="font-mono text-sm"
   134→        />
   135→        <p className="text-xs text-muted-foreground">Only show/notify versions matching this pattern</p>
   136→      </div>
   137→      <div className="space-y-2">
   138→        <Label htmlFor="version_filter_exclude">Version Filter — Exclude (regex, optional)</Label>
   139→        <Input
   140→          id="version_filter_exclude"
   141→          value={versionFilterExclude}
   142→          onChange={(e) => setVersionFilterExclude(e.target.value)}
   143→          placeholder='e.g. -(alpha|beta|rc|nightly)'
   144→          className="font-mono text-sm"
   145→        />
   146→        <p className="text-xs text-muted-foreground">Hide/suppress versions matching this pattern</p>
   147→      </div>
   148→      {provider === "github" && (
   149→        <div className="flex items-center gap-3">
   150→          <Switch checked={excludePrereleases} onCheckedChange={setExcludePrereleases} />
   151→          <Label>Exclude Pre-Releases</Label>
