package ingestion

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"os"
	"time"
)

const defaultGitHubAPIURL = "https://api.github.com"

// ghRelease represents a single release from the GitHub REST API.
type ghRelease struct {
	TagName     string `json:"tag_name"`
	Body        string `json:"body"`
	HTMLURL     string `json:"html_url"`
	PublishedAt string `json:"published_at"`
	Prerelease  bool   `json:"prerelease"`
	Draft       bool   `json:"draft"`
}

// GitHubSource polls the GitHub REST API for repository releases.
type GitHubSource struct {
	client     *http.Client
	repository string
	baseURL    string
	sourceID   string
}

func NewGitHubSource(client *http.Client, repository string, sourceID string) *GitHubSource {
	return &GitHubSource{
		client:     client,
		repository: repository,
		baseURL:    defaultGitHubAPIURL,
		sourceID:   sourceID,
	}
}

func (s *GitHubSource) Name() string    { return "github" }
func (s *GitHubSource) SourceID() string { return s.sourceID }

func (s *GitHubSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
	url := fmt.Sprintf("%s/repos/%s/releases?per_page=30", s.baseURL, s.repository)

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, fmt.Errorf("create request: %w", err)
	}
	req.Header.Set("Accept", "application/vnd.github+json")

	if token := os.Getenv("GITHUB_TOKEN"); token != "" {
		req.Header.Set("Authorization", "Bearer "+token)
	}

	resp, err := s.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("fetch releases: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
	}

	var releases []ghRelease
	if err := json.NewDecoder(resp.Body).Decode(&releases); err != nil {
		return nil, fmt.Errorf("decode releases: %w", err)
	}

	results := make([]IngestionResult, 0, len(releases))
	for _, rel := range releases {
		if rel.Draft {
			continue
		}
		if rel.TagName == "" {
			continue
		}

		ts, _ := time.Parse(time.RFC3339, rel.PublishedAt)

		prerelease := "false"
		if rel.Prerelease {
			prerelease = "true"
		}

		results = append(results, IngestionResult{
			Repository: s.repository,
			RawVersion: rel.TagName,
			Changelog:  rel.Body,
			Metadata: map[string]string{
				"release_url": rel.HTMLURL,
				"prerelease":  prerelease,
			},
			Timestamp: ts,
		})
	}
	return results, nil
}

package ingestion

import (
	"context"
	"fmt"
	"log/slog"
	"net/http"

	"github.com/jackc/pgx/v5/pgxpool"
)

// SourceLoader reads source configuration from the database and constructs
// IIngestionSource instances. It bridges the API-managed sources table with
// the polling orchestrator.
type SourceLoader struct {
	pool   *pgxpool.Pool
	client *http.Client
}

func NewSourceLoader(pool *pgxpool.Pool, client *http.Client) *SourceLoader {
	return &SourceLoader{pool: pool, client: client}
}

// LoadEnabledSources queries all enabled sources and constructs the
// appropriate IIngestionSource for each one based on provider.
func (l *SourceLoader) LoadEnabledSources(ctx context.Context) ([]IIngestionSource, error) {
	rows, err := l.pool.Query(ctx,
		`SELECT id, provider, repository FROM sources WHERE enabled = true`)
	if err != nil {
		return nil, fmt.Errorf("query enabled sources: %w", err)
	}
	defer rows.Close()

	var sources []IIngestionSource
	for rows.Next() {
		var id string
		var sourceType, repository string
		if err := rows.Scan(&id, &sourceType, &repository); err != nil {
			return nil, fmt.Errorf("scan source row: %w", err)
		}

		src := l.buildSource(id, sourceType, repository)
		if src == nil {
			slog.Warn("unsupported source type, skipping",
				"id", id, "type", sourceType, "repo", repository)
			continue
		}
		sources = append(sources, src)
	}
	return sources, rows.Err()
}

// LookupSourceID finds the source ID for a given (provider, repository) pair.
// Returns empty string and false if no matching enabled source exists.
func (l *SourceLoader) LookupSourceID(ctx context.Context, provider, repository string) (string, bool) {
	var id string
	err := l.pool.QueryRow(ctx,
		`SELECT id FROM sources WHERE provider = $1 AND repository = $2 AND enabled = true`,
		provider, repository,
	).Scan(&id)
	if err != nil {
		return "", false
	}
	return id, true
}

func (l *SourceLoader) buildSource(id string, sourceType, repository string) IIngestionSource {
	return BuildSource(l.client, id, sourceType, repository)
}

// BuildSource constructs the appropriate IIngestionSource based on provider type.
func BuildSource(client *http.Client, id string, sourceType, repository string) IIngestionSource {
	switch sourceType {
	case "dockerhub":
		return NewDockerHubSource(client, repository, id)
	case "github":
		return NewGitHubSource(client, repository, id)
	case "ecr-public":
		return NewECRPublicSource(client, repository, id)
	default:
		return nil
	}
}

